    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < N) {
        parent[tid] = tid;  // Each vertex starts as its own component
    }

__global__ void wcc_hook_phase(
    int* parent, 
    const int* row_ptr, 
    const int* col_idx, 
    int N,
    bool* changed
) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= N) return;

    int v = tid;
    int root_v = find_root_atomic(parent, v);

    // Process all edges of vertex v
    for (int e = row_ptr[v]; e < row_ptr[v + 1]; e++) {
        int u = col_idx[e];
        if (u >= N) continue;  // Safety check

        int root_u = find_root_atomic(parent, u);

        if (root_v != root_u) {
            // Atomic union operation
            int lo = min(root_v, root_u);
            int hi = max(root_v, root_u);

            int old_hi = atomicCAS(&parent[hi], hi, lo);
            if (old_hi == hi) {
                *changed = true;
                if (lo == root_u) root_v = lo;  // Update local root if needed
            } else if (old_hi != lo) {
                // CAS failed, retry with new value
                root_v = find_root_atomic(parent, v);
            }

extern "C" __global__ void vector_add(
    const float* __restrict__ a,
    const float* __restrict__ b,
    float* __restrict__ c,
    int n
) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = tid; i < n; i += stride) {
        c[i] = a[i] + b[i];
    }
}

extern "C" __global__ void matmul_simple(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            sum += A[row * K + k] * B[k * N + col];
        }
        C[row * N + col] = sum;
    }
}

extern "C" __global__ void bfs_kernel(
    const int* __restrict__ row_ptr,
    const int* __restrict__ col_idx,
    int* __restrict__ frontier,
    int* __restrict__ distances,
    int* __restrict__ next_frontier,
    int* __restrict__ next_size,
    int source,
    int level
) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Each thread processes one vertex
    if (tid < *next_size) {
        int v = next_frontier[tid];

        // Explore neighbors
        for (int e = row_ptr[v]; e < row_ptr[v + 1]; e++) {
            int u = col_idx[e];

            // Try to claim this vertex
            if (atomicCAS(&distances[u], -1, level + 1) == -1) {
                // Successfully discovered
                int idx = atomicAdd(next_size, 1);
                frontier[idx] = u;
            }
        }
    }
}

extern "C" __global__ void warp_reduce_sum(
    const float* __restrict__ input,
    float* __restrict__ output,
    int n
) {
    int tid = threadIdx.x;
    int lane = tid & 31;  // Lane ID within warp
    int wid = tid >> 5;  // Warp ID

    // Load data into shared memory
    extern __shared__ float sdata[];
    sdata[tid] = (tid < n) ? input[tid] : 0.0f;
    __syncthreads();

    // Warp-level reduction using shuffle
    float val = sdata[tid];

    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }

    // First thread in warp writes result
    if (lane == 0) {
        output[wid] = val;
    }
}
